#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

import argparse
from pathlib import Path

from wiki_common import (
    WIKI_OPERATION_CREATE,
    append_index_reference,
    enforce_wiki_update_authorization,
    is_indexed_wiki_path,
    is_path_within,
    parse_root_prefixed_wiki_path,
    repo_root,
    select_wiki_root,
    wiki_update_operation_for_target,
)


SECTION_PREFIX = '## Update: '
WHY_HEADER = '### Why'
RULES_HEADER = '### Rules / Contracts'
NOTES_HEADER = '### Validation / Notes'


def update_block_ranges(lines: list[str], title: str) -> list[tuple[int, int]]:
    marker = f'{SECTION_PREFIX}{title}'
    starts = [i for i, line in enumerate(lines) if line.strip() == marker]
    ranges: list[tuple[int, int]] = []
    for start in starts:
        end = len(lines)
        for i in range(start + 1, len(lines)):
            if lines[i].startswith(SECTION_PREFIX):
                end = i
                break
        ranges.append((start, end))
    return ranges


def find_header(lines: list[str], header: str) -> int | None:
    for i, line in enumerate(lines):
        if line.strip() == header:
            return i
    return None


def section_slice(lines: list[str], header: str) -> tuple[int, int] | None:
    start = find_header(lines, header)
    if start is None:
        return None
    end = len(lines)
    for i in range(start + 1, len(lines)):
        if lines[i].startswith('### ') and lines[i].strip() != header:
            end = i
            break
    return start, end


def bullet_lines(text: str) -> list[str]:
    return [line.strip()[2:] for line in text.splitlines() if line.strip().startswith('- ')]


def render_update_block(title: str, why: str, rules: list[str], notes: list[str] | None = None) -> str:
    notes = notes or ['<fill-me>']
    lines = [
        f'## Update: {title}',
        '',
        WHY_HEADER,
        f'- {why}',
        '',
        RULES_HEADER,
    ]
    if rules:
        lines.extend(f'- {rule}' for rule in rules)
    else:
        lines.append('- <fill-me>')
    lines.extend([
        '',
        NOTES_HEADER,
    ])
    lines.extend(f'- {note}' for note in notes)
    lines.extend(['',])
    return '\n'.join(lines)


def merge_update_block(existing: str, title: str, why: str, rules: list[str]) -> str:
    lines = existing.splitlines()
    ranges = update_block_ranges(lines, title)

    if not ranges:
        if existing and not existing.endswith('\n'):
            existing += '\n'
        if existing.strip():
            existing += '\n'
        return existing + render_update_block(title, why, rules) + '\n'

    keep_start, keep_end = ranges[0]
    block_lines = lines[keep_start:keep_end]

    rules_slice = section_slice(block_lines, RULES_HEADER)
    notes_slice = section_slice(block_lines, NOTES_HEADER)

    existing_rules = []
    existing_notes = ['<fill-me>']
    if rules_slice:
        _, end = rules_slice
        existing_rules = [item for item in bullet_lines('\n'.join(block_lines[rules_slice[0] + 1:end])) if item != '<fill-me>']
    if notes_slice:
        _, end = notes_slice
        extracted = bullet_lines('\n'.join(block_lines[notes_slice[0] + 1:end]))
        if extracted:
            existing_notes = extracted

    merged_rules: list[str] = []
    for item in rules + existing_rules:
        if item and item not in merged_rules:
            merged_rules.append(item)

    merged_block = render_update_block(title, why, merged_rules, existing_notes)
    new_lines = lines[:keep_start] + merged_block.splitlines() + lines[keep_end:]

    duplicate_ranges = update_block_ranges(new_lines, title)[1:]
    for start, end in reversed(duplicate_ranges):
        del new_lines[start:end]

    return '\n'.join(new_lines).rstrip() + '\n'


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description='Mechanical wiki update writer; decide target ownership and duplicate coverage before running it.'
    )
    parser.add_argument('--wiki-root', choices=['project', 'shared'], default=None, help='Wiki root to update')
    parser.add_argument('--authorized-update', action='store_true', help='The user authorized updating an existing wiki page')
    parser.add_argument('--authorized-create', action='store_true', help='The user authorized creating a new wiki document')
    parser.add_argument('target', help='Agent-decided target path, root-relative or root-prefixed')
    parser.add_argument('title')
    parser.add_argument('why')
    parser.add_argument('rules', nargs='*')
    return parser.parse_args()


def main() -> int:
    args = parse_args()
    target_rel = args.target
    title = args.title.strip()
    why = args.why.strip()
    rules = [rule.strip() for rule in args.rules if rule.strip()]

    root = repo_root(Path.cwd())
    prefixed = parse_root_prefixed_wiki_path(root, target_rel)
    if prefixed:
        root_desc, relative = prefixed
        if args.wiki_root and root_desc.name != args.wiki_root:
            raise SystemExit(f'Path root {root_desc.name} conflicts with --wiki-root {args.wiki_root}')
    else:
        root_desc = select_wiki_root(root, args.wiki_root or 'project', create=True)
        relative = Path(target_rel)

    wiki_root = root_desc.path
    wiki_root.mkdir(parents=True, exist_ok=True)
    target = (wiki_root / relative).resolve()
    if not is_path_within(wiki_root.resolve(), target):
        raise SystemExit(f'Invalid target: {target_rel}')
    if target.suffix != '.md':
        raise SystemExit(f'Target must be a markdown file: {target_rel}')
    if target.name == 'index.md':
        raise SystemExit('Use leaf wiki page files for durable update bodies; index.md is reserved for navigation')

    target_exists = target.exists()
    try:
        enforce_wiki_update_authorization(
            root,
            root_desc,
            wiki_update_operation_for_target(target_exists),
            authorized_update=args.authorized_update,
            authorized_create=args.authorized_create,
        )
    except PermissionError as exc:
        raise SystemExit(str(exc)) from exc
    except ValueError as exc:
        raise SystemExit(str(exc)) from exc

    target.parent.mkdir(parents=True, exist_ok=True)
    if not target_exists:
        target.write_text(f'# {title}\n\n', encoding='utf-8')
    if not is_indexed_wiki_path(wiki_root, target, include_indexes=False):
        if not (wiki_root / 'index.md').exists():
            try:
                enforce_wiki_update_authorization(
                    root,
                    root_desc,
                    WIKI_OPERATION_CREATE,
                    authorized_create=args.authorized_create,
                )
            except PermissionError as exc:
                raise SystemExit(str(exc)) from exc
            except ValueError as exc:
                raise SystemExit(str(exc)) from exc
        append_index_reference(wiki_root, target)

    existing = target.read_text(encoding='utf-8')
    updated = merge_update_block(existing, title, why, rules)
    target.write_text(updated, encoding='utf-8')
    print(f'Updated wiki page body: {target}')
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
